SELECT COUNT(*) AS total_search_warrant_cases
FROM cases
WHERE is_search_warrant = 1;

SELECT COUNT(doc_id) AS document_count
FROM documents
WHERE case_id = 123;

SELECT COUNT(DISTINCT case_id) AS total_cases_with_search_warrant_pending
FROM cases
WHERE is_search_warrant = 1 AND status = 'pending';

SELECT COUNT(doc_id) AS total_documents_uploaded
FROM documents
WHERE created_by_user_id = (SELECT user_id FROM users WHERE user_name = 'John Doe');

SELECT COUNT(*) AS high_priority_case_count
FROM cases
WHERE priority = 'high';

SELECT c.case_name, co.court_name
FROM cases c
JOIN courts co ON c.court_id = co.court_id;
